css:
#mod-fase2-1 .f21-toolbar{display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;flex-wrap:wrap;gap:12px}
#mod-fase2-1 .f21-search-group{display:flex;gap:10px;flex-wrap:wrap;flex:1;min-width:300px}
#mod-fase2-1 .f21-search-box{position:relative;flex:1;min-width:200px}
#mod-fase2-1 .f21-search-box i{position:absolute;left:12px;top:50%;transform:translateY(-50%);color:#64748b;font-size:13px}
#mod-fase2-1 .f21-search-box input{width:100%;padding:10px 12px 10px 36px;border-radius:8px;border:1px solid #334155;background:#0f172a;color:#f1f5f9;font-size:13px;outline:none}
#mod-fase2-1 .f21-search-box input:focus{border-color:#3b82f6}
#mod-fase2-1 .f21-search-group select{padding:10px 12px;border-radius:8px;border:1px solid #334155;background:#0f172a;color:#f1f5f9;font-size:13px;outline:none;min-width:140px}
#mod-fase2-1 .f21-search-group select:focus{border-color:#3b82f6}
#mod-fase2-1 .f21-actions{display:flex;gap:8px}
#mod-fase2-1 .f21-stats-row{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin-bottom:20px}
#mod-fase2-1 .f21-stat-card{background:#1e293b;border:1px solid #334155;border-radius:12px;padding:16px;display:flex;align-items:center;gap:12px;transition:.2s}
#mod-fase2-1 .f21-stat-card:hover{border-color:#3b82f6}
#mod-fase2-1 .f21-stat-icon{width:40px;height:40px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:16px}
#mod-fase2-1 .f21-stat-icon.blue{background:rgba(59,130,246,.15);color:#3b82f6}
#mod-fase2-1 .f21-stat-icon.green{background:rgba(16,185,129,.15);color:#10b981}
#mod-fase2-1 .f21-stat-icon.red{background:rgba(239,68,68,.15);color:#ef4444}
#mod-fase2-1 .f21-stat-icon.amber{background:rgba(245,158,11,.15);color:#f59e0b}
#mod-fase2-1 .f21-stat-value{font-size:20px;font-weight:700;color:#f1f5f9}
#mod-fase2-1 .f21-stat-label{font-size:11px;color:#94a3b8;margin-top:2px}
#mod-fase2-1 .f21-table-wrapper{background:#1e293b;border:1px solid #334155;border-radius:12px;overflow:hidden}
#mod-fase2-1 .f21-table-wrapper .data-table{margin:0}
#mod-fase2-1 .f21-table-wrapper .data-table th{background:#334155}
#mod-fase2-1 .f21-table-wrapper .data-table td{padding:10px 12px;font-size:12px}
#mod-fase2-1 .f21-table-wrapper .data-table tr:hover td{background:rgba(255,255,255,.03)}
#mod-fase2-1 .f21-stock-bar{height:6px;border-radius:3px;background:#334155;overflow:hidden;margin-top:4px;width:80px}
#mod-fase2-1 .f21-stock-bar-fill{height:100%;border-radius:3px;transition:width .3s}
#mod-fase2-1 .f21-stock-bar-fill.ok{background:#10b981}
#mod-fase2-1 .f21-stock-bar-fill.bajo{background:#f59e0b}
#mod-fase2-1 .f21-stock-bar-fill.critico{background:#ef4444}
#mod-fase2-1 .f21-modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:2000;display:none;align-items:center;justify-content:center;padding:20px}
#mod-fase2-1 .f21-modal-overlay.active{display:flex}
#mod-fase2-1 .f21-modal{background:#1e293b;border:1px solid #334155;border-radius:12px;width:100%;max-width:600px;max-height:90vh;overflow-y:auto;animation:modalIn .2s}
#mod-fase2-1 .f21-modal-header{padding:20px 20px 0;display:flex;align-items:center;justify-content:space-between}
#mod-fase2-1 .f21-modal-title{font-size:16px;font-weight:600;color:#f1f5f9}
#mod-fase2-1 .f21-modal-close{width:32px;height:32px;border-radius:6px;background:#334155;border:none;color:#f1f5f9;cursor:pointer;font-size:18px;display:flex;align-items:center;justify-content:center}
#mod-fase2-1 .f21-modal-close:hover{background:#ef4444}
#mod-fase2-1 .f21-modal-body{padding:20px}
#mod-fase2-1 .f21-form-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:16px}
#mod-fase2-1 .f21-modal-footer{padding:0 20px 20px;display:flex;justify-content:flex-end;gap:10px}
@media(max-width:600px){#mod-fase2-1 .f21-form-grid{grid-template-columns:1fr}}

