  var html_content = "<div id=\"mod-fase2-1\">\n  <h1 class=\"page-title\"><i class=\"fas fa-boxes\"></i> Materias Primas</h1>\n  <p class=\"page-subtitle\">Inventario de materias primas - Fase 2.1</p>\n\n  <div class=\"f21-toolbar\">\n    <div class=\"f21-search-group\">\n      <div class=\"f21-search-box\">\n        <i class=\"fas fa-search\"></i>\n        <input type=\"text\" id=\"f21-search\" placeholder=\"Buscar por codigo, nombre o categoria...\" oninput=\"window.f21_filtrar()\">\n      </div>\n      <select id=\"f21-filter-cat\" onchange=\"window.f21_filtrar()\">\n        <option value=\"\">Todas las categorias</option>\n      </select>\n      <select id=\"f21-filter-stock\" onchange=\"window.f21_filtrar()\">\n        <option value=\"\">Todos los stocks</option>\n        <option value=\"bajo\">Stock Bajo</option>\n        <option value=\"ok\">Stock OK</option>\n        <option value=\"cero\">Sin Stock</option>\n      </select>\n    </div>\n    <div class=\"f21-actions\">\n      <button class=\"btn btn-primary\" onclick=\"window.f21_abrirModal()\">\n        <i class=\"fas fa-plus\"></i> Agregar Material\n      </button>\n      <button class=\"btn btn-secondary\" onclick=\"window.f21_exportarCSV()\">\n        <i class=\"fas fa-file-csv\"></i> Exportar\n      </button>\n    </div>\n  </div>\n\n  <div class=\"f21-stats-row\">\n    <div class=\"f21-stat-card\">\n      <div class=\"f21-stat-icon blue\"><i class=\"fas fa-cubes\"></i></div>\n      <div class=\"f21-stat-info\">\n        <div class=\"f21-stat-value\" id=\"f21-stat-total\">0</div>\n        <div class=\"f21-stat-label\">Total Materiales</div>\n      </div>\n    </div>\n    <div class=\"f21-stat-card\">\n      <div class=\"f21-stat-icon green\"><i class=\"fas fa-check-circle\"></i></div>\n      <div class=\"f21-stat-info\">\n        <div class=\"f21-stat-value\" id=\"f21-stat-ok\">0</div>\n        <div class=\"f21-stat-label\">Stock OK</div>\n      </div>\n    </div>\n    <div class=\"f21-stat-card\">\n  