abel>Nombre</label>\n            <input type=\"text\" id=\"f21-nombre\" placeholder=\"Nombre del material\">\n          </div>\n          <div class=\"form-group\">\n            <label>Categoria</label>\n            <select id=\"f21-categoria\"></select>\n          </div>\n          <div class=\"form-group\">\n            <label>Unidad</label>\n            <select id=\"f21-unidad\"></select>\n          </div>\n          <div class=\"form-group\">\n            <label>Stock Inicial</label>\n            <input type=\"number\" id=\"f21-stock\" placeholder=\"0\" min=\"0\" step=\"0.01\">\n          </div>\n          <div class=\"form-group\">\n            <label>Stock Minimo</label>\n            <input type=\"number\" id=\"f21-stockMin\" placeholder=\"0\" min=\"0\" step=\"0.01\">\n          </div>\n          <div class=\"form-group\">\n            <label>Costo Unitario</label>\n            <input type=\"number\" id=\"f21-costo\" placeholder=\"0.00\" min=\"0\" step=\"0.01\">\n          </div>\n          <div class=\"form-group\">\n            <label>Moneda Costo</label>\n            <select id=\"f21-monedaCosto\">\n              <option value=\"VES\">VES (Bolivar)</option>\n              <option value=\"USD\">USD (Dolar)</option>\n              <option value=\"EUR\">EUR (Euro)</option>\n            </select>\n          </div>\n          <div class=\"form-group\" style=\"grid-column:1/-1\">\n            <label>Descripcion</label>\n            <textarea id=\"f21-descripcion\" placeholder=\"Descripcion del material...\"></textarea>\n          </div>\n        </div>\n      </div>\n      <div class=\"f21-modal-footer\">\n        <button class=\"btn btn-secondary\" onclick=\"window.f21_cerrarModal()\">Cancelar</button>\n        <button class=\"btn btn-primary\" onclick=\"window.f21_guardar()\">\n          <i class=\"fas fa-save\"></i> Guardar\n        </button>\n      </div>\n    </div>\n  </div>\n</div>";
  var css_content = "#mod-fase2-1 .f21-toolbar{display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;flex-wrap:wrap;gap:12px}\n#mod-fase2-1 .f21-search-group{display:flex;gap:10px;flex-wrap:wrap;flex:1;min-width:300px}\n#mod-fase2-1 .f21-search-box{position:relative;flex:1;min-width:200px}\n#mod-fase2-1 .f21-search-box i{position:absolute;left:12px;top:50%;transform:translateY(-50%);color:#64748b;font-size:13px}\n#mod-fase2-1 .f21-search-box input{width:100%;padding:10px 12px 10px 36px;border-radius:8px;border:1px solid #334155;background:#0f172a;color:#f1f5f9;font-size:13px;outline:none}\n#mod-fase2-1 .f21-search-box input:focus{border-color:#3b82f6}\n#mod-fase2-1 .f21-search-group select{padding:10px 12px;border-radius:8px;border:1px solid #334155;background:#0f172a;color:#f1f5f9;font-size:13px;outline:none;min-width:140px}\n#mod-fase2-1 .f21-search-group select:focus{border-color:#3b82f6}\n#mod-fase2-1 .f21-actions{display:flex;gap:8px}\n#mod-fase2-1 .f21-stats-row{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin-bottom:20px}\n#mod-fase2-1 .f21-stat-card{background:#1e293b;border:1px solid #334155;border-radius:12px;padding:16px;display:flex;align-items:center;gap:12px;transition:.2s}\n#mod-fase2-1 .f21-stat-card:hover{border-color:#3b82f6}\n#mod-fase2-1 .f21-stat-icon{width:40px;height:40px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:16px}\n#mod-fase2-1 .f21-stat-icon.blue{background:rgba(59,130,246,.15);color:#3b82f6}\n#mod-fase2-1 .f21-stat-icon.green{background:rgba(16,185,129,.15);color:#10b981}\n#mod-fase2-1 .f21-stat-icon.red{background:rgba(239,68,68,.15);color:#ef4444}\n#mod-fase2-1 .f21-stat-icon.amber{background:rgba(245,158,11,.15);color:#f59e0b}\n#mod-fase2-1 .f21-stat-value{font-size:20px;font-weight:700;color:#f1f5f9}\n#mod-fase2-1 .f21-stat-label{font-size:11px;color:#94a3b8;margin-top:2px}\n#mod-fase2-1 .f21-table-wrapper{background:#1e293b;border:1px solid #334155;border-radius:12px;overflow:hidden}\n#mod-fase2-1 .f21-table-wrapper .data-table{margin:0}\n#mod-fase2-1 .f21-table-wrapper .data-table th{background:#334155}\n#mod-fase2-1 .f21-table-wrapper .data-table td{padding:10px 12px;font-size:12px}\n#mod-fase2-1 .f21-table-wrapper .data-table tr:hover td{background:rgba(255,255,255,.03)}\n#mod-fase2-1 .f21-stock-bar{height:6px;border-radius:3px;background:#334155;overflow:hidden;margin-top:4px;width:80px}\n#mod-fase2-1 .f21-stock-bar-fill{height:100%;border-radius:3px;transition:width .3s}\n#mod-fase2-1 .f21-stock-bar-fill.ok{background:#10b981}\n#mod-fase2-1 .f21-stock-bar-fill.bajo{background:#f59e0b}\n#mod-fase2-1 .f21-stock-bar-fill.critico{background:#ef4444}\n#mod-fase2-1 .f21-modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:2000;display:none;align-items:center;justify-content:center;padding:20px}\n#mod-fase2-1 .f21-modal-overlay.active{display:flex}\n#mod-fase2-1 .f21-modal{background:#1e293b;border:1px solid #334155;border-radius:12px;width:100%;max-width:600px;max-height:90vh;overflow-y:auto;animation:modalIn .2s}\n#mod-fase2-1 .f21-modal-header{padding:20px 20px 0;display:flex;align-items:center;justify-content:space-between}\n#mod-fase2-1 .f21-modal-title{font-size:16px;font-weight:600;color:#f1f5f9}\n#mod-fase2-1 .f21-modal-close{width:32px;height:32px;border-radius:6px;background:#334155;border:none;color:#f1f5f9;cursor:pointer;font-size:18px;display:flex;align-items:center;justify-content:center}\n#mod-fase2-1 .f21-modal-close:hover{background:#ef4444}\n#mod-fase2-1 .f21-modal-body{padding:20px}\n#mod-fase2-1 .f21-form-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:16px}\n#mod-fase2-1 .f21-modal-footer{padding:0 20px 20px;display:flex;justify-content:flex-end;gap:10px}\n@media(max-width:600px){#mod-fase2-1 .f21-form-grid{grid-template-columns:1fr}}";

  function init() {
    var db = erp.getDB();
    if (!db.materiasPrimas) db.materiasPrimas = [];
    if (!db.categorias) db.categorias = [];
    if (!db.unidades) db.unidades = [];

    if (db.materiasPrimas.length === 0) {
      db.materiasPrimas = [
        {id:"MP001", codigo:"MP001", nombre:"Hidroxido de Sodio", categoria:"Bases", unidad:"kg", stock:850, stockMin:200, costoUnitario:2.5, monedaCostoBase:"USD", descripcion:"Base alcalina para formulacion de limpiadores"},
        {id:"MP002", codigo:"MP002", nombre:"Acido Clorhidrico", categoria:"Acidos", unidad:"L", stock:420, stockMin:100, costoUnitario:1.8, monedaCostoBase:"USD", descripcion:"Acido industrial para desincrustantes"},
        {id:"MP003", codigo:"MP003", nombre:"Hipoclorito de Sodio", categoria:"Desinfectantes", unidad:"L", stock:600, stockMin:150, costoUnitario:1.2, monedaCostoBase:"USD", descripcion:"Blanqueador y desinfectante"},
        {id:"MP004", codigo:"MP004", nombre:"Envase Plastico 1L", categoria:"Empaque", unidad:"und", stock:1200, stockMin:300, costoUnitario:0.45, monedaCostoBase:"USD", descripcion:"Botella PET con tapa rosca"},
        {id:"MP005", codigo:"MP005", nombre:"Lauril Eter Sulfato", categoria:"Bases", unidad:"kg", stock:350, stockMin:100, costoUnitario:3.2, monedaCostoBase:"USD", descripcion:"Tensioactivo anionico para detergentes"}
      ];
      erp.saveLocal(db);
      erp.showToast("info", "Datos Demo", "5 materiales de demostracion cargados");
    }

    cargarSelects();
    renderTabla();
    actualizarStats();
  }

  function cargarSelects() {
    var db = erp.getDB();
    var selCat = document.getElementById("f21-categoria");
    var selFilterCat = document.getElementById("f21-filter-cat");
    var selUnidad = document.getElementById("f21-unidad");

    if (selCat) {
      selCat.innerHTML = '<option value="">Seleccione...</option>' +
        (db.categorias || []).map(function(c) {
          return '<option value="' + c.nombre + '">' + c.nombre + '</option>';
        }).join("");
    }

    if (selFilterCat) {
      var opts = '<option value="">Todas las categorias</option>' +
        (db.categorias || []).map(function(c) {
          return '<option value="' + c.nombre + '">' + c.nombre + '</option>';
        }).join("");
      selFilterCat.innerHTML = opts;
    }

    if (selUnidad) {
      selUnidad.innerHTML = '<option value="">Seleccione...</option>' +
        (db.unidades || []).map(function(u) {
          return '<option value="' + u.simbolo + '">' + u.nombre + ' (' + u.simbolo + ')</option>';
        }).join("");
    }
  }

  function getEstadoStock(stock, minimo) {
    if (stock <= 0) return {clase: "critico", texto: "Sin Stock", badge: "badge-danger"};
    if (stock < minimo) return {clase: "bajo", texto: "Bajo", badge: "badge-warning"};
    return {clase: "ok", texto: "OK", badge: "badge-success"};
  }

  function calcularPorcentajeStock(stock, minimo) {
    if (minimo <= 0) return stock > 0 ? 100 : 0;
    var pct = (stock / minimo) * 100;
    return Math.min(pct, 100);
  }

  function renderTabla() {
    var db = erp.getDB();
    var tbody = document.getElementById("f21-tbody");
    var empty = document.getElementById("f21-empty");
    var tabla = document.getElementById("f21-tabla");
    if (!tbody) return;

    var materiales = db.materiasPrimas || [];

    var busqueda = (document.getElementById("f21-search") ? document.getElementById("f21-search").value : "").toLowerCase();
    var catFilter = document.getElementById("f21-filter-cat") ? document.getElementById("f21-filter-cat").value : "";
    var stockFilter = document.getElementById("f21-filter-stock") ? document.getElementById("f21-filter-stock").value : "";

    var filtrados = materiales.filter(function(m) {
      var matchBusqueda = !busqueda || 
        (m.codigo && m.codigo.toLowerCase().indexOf(busqueda) >= 0) ||
        (m.nombre && m.nombre.toLowerCase().indexOf(busqueda) >= 0) ||
        (m.categoria && m.categoria.toLowerCase().indexOf(busqueda) >= 0);
      var matchCat = !catFilter || m.categoria === catFilter;
      var matchStock = true;
      if (stockFilter === "bajo") matchStock = m.stock < m.stockMin && m.stock > 0;
      else if (stockFilter === "ok") matchStock = m.stock >= m.stockMin;
      else if (stockFilter === "cero") matchStock = m.stock <= 0;
      return matchBusqueda && matchCat && matchStock;
    });

    if (filtrados.length === 0) {
      tbody.innerHTML = "";
      if (empty) empty.style.display = "block";
      if (tabla) tabla.style.display = "none";
    } else {
      if (empty) empty.style.display = "none";
      if (tabla) tabla.style.display = "table";

      tbody.innerHTML = filtrados.map(function(m) {
        var estado = getEstadoStock(m.stock || 0, m.stockMin || 0);
        var pct = calcularPorcentajeStock(m.stock || 0, m.stockMin || 0);
        var costoFmt = erp.formatearMoneda(m.costoUnitario || 0, m.monedaCostoBase || "VES");
        var stockVal = (m.stock || 0).toLocaleString("es-VE", {minimumFractionDigits: 2, maximumFractionDigits: 2});
        var stockMinVal = (m.stockMin || 0).toLocaleString("es-VE", {minimumFractionDigits: 2, maximumFractionDigits: 2});

        return '<tr>' +
          '<td><strong>' + (m.codigo || "-") + '</strong></td>' +
          '<td>' + (m.nombre || "-") + '</td>' +
          '<td><span class="badge badge-blue">' + (m.categoria || "-") + '</span></td>' +
          '<td>' + (m.unidad || "-") + '</td>' +
          '<td>' +
            '<div>' + stockVal + '</div>' +
            '<div class="f21-stock-bar"><div class="f21-stock-bar-fill ' + estado.clase + '" style="width:' + pct + '%"></div></div>' +
          '</td>' +
          '<td>' + stockMinVal + '</td>' +
          '<td><strong>' + costoFmt + '</strong></td>' +
          '<td>' + (m.monedaCostoBase || "-") + '</td>' +
          '<td><span class="badge ' + estado.badge + '">' + estado.texto + '</span></td>' +
          '<td class="actions">' +
            '<button class="btn btn-primary btn-sm" onclick="window.f21_editar(&quot;' + m.id + '&quot;)" title="Editar"><i class="fas fa-edit"></i></button>' +
            '<button class="btn btn-danger btn-sm" onclick="window.f21_eliminar(&quot;' + m.id + '&quot;)" title="Eliminar"><i class="fas fa-trash"></i></button>' +
          '</td>' +
        '</tr>';
      }).join("");
    }

    actualizarStats();
  }

  function actualizarStats() {
    var db = erp.getDB();
    var materiales = db.materiasPrimas || [];
    var busqueda = (document.getElementById("f21-search") ? document.getElementById("f21-search").value : "").toLowerCase();
    var catFilter = document.getElementById("f21-filter-cat") ? document.getElementById("f21-filter-cat").value : "";
    var stockFilter = document.getElementById("f21-filter-stock") ? document.getElementById("f21-filter-stock").value : "";

    var filtrados = materiales.filter(function(m) {
      var matchBusqueda = !busqueda || 
        (m.codigo && m.codigo.toLowerCase().indexOf(busqueda) >= 0) ||
        (m.nombre && m.nombre.toLowerCase().indexOf(busqueda) >= 0);
      var matchCat = !catFilter || m.categoria === catFilter;
      var matchStock = true;
      if (stockFilter === "bajo") matchStock = m.stock < m.stockMin && m.stock > 0;
      else if (stockFilter === "ok") matchStock = m.stock >= m.stockMin;
      else if (stockFilter === "cero") matchStock = m.stock <= 0;
      return matchBusqueda && matchCat && matchStock;
    });

    var total = filtrados.length;
    var ok = filtrados.filter(function(m) { return (m.stock || 0) >= (m.stockMin || 0); }).length;
    var bajo = filtrados.filter(function(m) { return (m.stock || 0) < (m.stockMin || 0) && (m.stock || 0) > 0; }).length;

    var valorTotal = 0;
    filtrados.forEach(function(m) {
      var conv = erp.convertirMoneda((m.costoUnitario || 0) * (m.stock || 0), m.monedaCostoBase || "VES", erp.config.monedaBase || "VES");
      valorTotal += conv.monto || 0;
    });

    var elTotal = document.getElementById("f21-stat-total");
    var elOk = document.getElementById("f21-stat-ok");
    var elBajo = document.getElementById("f21-stat-bajo");
    var elValor = document.getElementById("f21-stat-valor");

    if (elTotal) elTotal.textContent = total;
    if (elOk) elOk.textContent = ok;
    if (elBajo) elBajo.textContent = bajo;
    if (elValor) elValor.textContent = erp.formatearMoneda(valorTotal, erp.config.monedaBase || "VES");
  }

  window.f21_filtrar = function() { renderTabla(); };

  window.f21_abrirModal = function(id) {
    editandoId = id || null;
    var modal = document.getElementById("f21-modal");
    var title = document.getElementById("f21-modal-title");
    if (modal) modal.classList.add("active");
    if (title) title.textContent = editandoId ? "Editar Material" : "Agregar Material";

    if (editandoId) {
      var db = erp.getDB();
      var m = (db.materiasPrimas || []).find(function(x) { return x.id === editandoId; });
      if (m) {
        document.getElementById("f21-codigo").value = m.codigo || "";
        document.getElementById("f21-nombre").value = m.nombre || "";
        document.getElementById("f21-categoria").value = m.categoria || "";
        document.getElementById("f21-unidad").value = m.unidad || "";
        document.getElementById("f21-stock").value = m.stock || 0;
        document.getElementById("f21-stockMin").value = m.stockMin || 0;
        document.getElementById("f21-costo").value = m.costoUnitario || 0;
        document.getElementById("f21-monedaCosto").value = m.monedaCostoBase || "VES";
        document.getElementById("f21-descripcion").value = m.descripcion || "";
      }
    } else {
      document.getElementById("f21-codigo").value = "";
      document.getElementById("f21-nombre").value = "";
      document.getElementById("f21-categoria").value = "";
      document.getElementById("f21-unidad").value = "";
      document.getElementById("f21-stock").value = "";
      document.getElementById("f21-stockMin").value = "";
      document.getElementById("f21-costo").value = "";
      document.getElementById("f21-monedaCosto").value = "VES";
      document.getElementById("f21-descripcion").value = "";
    }
  };

  window.f21_cerrarModal = function() {
    var modal = document.getElementById("f21-modal");
    if (modal) modal.classList.remove("active");
    editandoId = null;
  };

  window.f21_guardar = function() {
    var codigo = document.getElementById("f21-codigo").value.trim();
    var nombre = document.getElementById("f21-nombre").value.trim();
    var categoria = document.getElementById("f21-categoria").value;
    var unidad = document.getElementById("f21-unidad").value;
    var stock = parseFloat(document.getElementById("f21-stock").value) || 0;
    var stockMin = parseFloat(document.getElementById("f21-stockMin").value) || 0;
    var costo = parseFloat(document.getElementById("f21-costo").value) || 0;
    var moneda = document.getElementById("f21-monedaCosto").value;
    var descripcion = document.getElementById("f21-descripcion").value.trim();

    if (!codigo || !nombre || !categoria || !unidad) {
      erp.showToast("warning", "Campos Requeridos", "Codigo, nombre, categoria y unidad son obligatorios");
      return;
    }

    var db = erp.getDB();
    if (!db.materiasPrimas) db.materiasPrimas = [];

    var duplicado = db.materiasPrimas.find(function(m) {
      return m.codigo === codigo && m.id !== editandoId;
    });
    if (duplicado) {
      erp.showToast("error", "Codigo Duplicado", "Ya existe un material con ese codigo");
      return;
    }

    if (editandoId) {
      var idx = db.materiasPrimas.findIndex(function(m) { return m.id === editandoId; });
      if (idx >= 0) {
        db.materiasPrimas[idx] = {
          id: editandoId,
          codigo: codigo,
          nombre: nombre,
          categoria: categoria,
          unidad: unidad,
          stock: stock,
          stockMin: stockMin,
          costoUnitario: costo,
          monedaCostoBase: moneda,
          descripcion: descripcion
        };
        erp.saveLocal(db);
        erp.showToast("success", "Actualizado", nombre + " modificado correctamente");
      }
    } else {
      var nuevo = {
        id: erp.genId("MP"),
        codigo: codigo,
        nombre: nombre,
        categoria: categoria,
        unidad: unidad,
        stock: stock,
        stockMin: stockMin,
        costoUnitario: costo,
        monedaCostoBase: moneda,
        descripcion: descripcion
      };
      db.materiasPrimas.push(nuevo);
      erp.saveLocal(db);
      erp.showToast("success", "Agregado", nombre + " registrado correctamente");
    }

    window.f21_cerrarModal();
    renderTabla();
  };

  window.f21_editar = function(id) {
    window.f21_abrirModal(id);
  };

  window.f21_eliminar = function(id) {
    erp.showConfirm("Eliminar Material", "Esta accion no se puede deshacer. ¿Continuar?", function() {
      var db = erp.getDB();
      var m = (db.materiasPrimas || []).find(function(x) { return x.id === id; });
      db.materiasPrimas = (db.materiasPrimas || []).filter(function(x) { return x.id !== id; });
      erp.saveLocal(db);
      erp.showToast("success", "Eliminado", (m ? m.nombre : "Material") + " eliminado");
      renderTabla();
    });
  };

  window.f21_exportarCSV = function() {
    var db = erp.getDB();
    var materiales = db.materiasPrimas || [];
    var busqueda = (document.getElementById("f21-search") ? document.getElementById("f21-search").value : "").toLowerCase();
    var catFilter = document.getElementById("f21-filter-cat") ? document.getElementById("f21-filter-cat").value : "";
    var stockFilter = document.getElementById("f21-filter-stock") ? document.getElementById("f21-filter-stock").value : "";

    var filtrados = materiales.filter(function(m) {
      var matchBusqueda = !busqueda || 
        (m.codigo && m.codigo.toLowerCase().indexOf(busqueda) >= 0) ||
        (m.nombre && m.nombre.toLowerCase().indexOf(busqueda) >= 0);
      var matchCat = !catFilter || m.categoria === catFilter;
      var matchStock = true;
      if (stockFilter === "bajo") matchStock = m.stock < m.stockMin && m.stock > 0;
      else if (stockFilter === "ok") matchStock = m.stock >= m.stockMin;
      else if (stockFilter === "cero") matchStock = m.stock <= 0;
      return matchBusqueda && matchCat && matchStock;
    });

    var csv = "Codigo,Nombre,Categoria,Unidad,Stock,Stock Minimo,Costo Unitario,Moneda,Descripcion\n";
    filtrados.forEach(function(m) {
      csv += '"' + (m.codigo || "") + '","' + (m.nombre || "") + '","' + (m.categoria || "") + '","' + 
             (m.unidad || "") + '",' + (m.stock || 0) + ',' + (m.stockMin || 0) + ',' + 
             (m.costoUnitario || 0) + ',"' + (m.monedaCostoBase || "") + '","' + (m.descripcion || "") + '"\n';
    });

    var blob = new Blob([csv], {type: "text/csv;charset=utf-8;"});
    var url = URL.createObjectURL(blob);
    var a = document.createElement("a");
    a.href = url;
    a.download = "MateriasPrimas_" + new Date().toISOString().split("T")[0] + ".csv";
    a.click();
    URL.revokeObjectURL(url);
    erp.showToast("success", "Exportado", filtrados.length + " registros exportados a CSV");
  };

